import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getToken } from "next-auth/jwt";

export async function GET(request: NextRequest) {
  try {
    const token = await getToken({
      req: request,
      secret: process.env.NEXTAUTH_SECRET,
    });
    if (!token?.id) {
      return NextResponse.json({ error: "Войдите в аккаунт" }, { status: 401 });
    }
    const patientId = parseInt(token.id as string);

    const appointments = await prisma.appointment.findMany({
      where: { patient_id: patientId },
      include: {
        specialist: true,
        service: { select: { id: true, title: true } },
      },
      orderBy: { scheduled_at: "desc" },
    });

    const list = appointments.map((a) => ({
      id: a.id,
      scheduled_at: a.scheduled_at,
      duration_minutes: a.duration_minutes,
      status: a.status,
      note: a.note,
      specialist: { id: a.specialist.id, name: a.specialist.name, specialization: a.specialist.specialization },
      service: a.service ? { id: a.service.id, title: a.service.title } : null,
    }));

    return NextResponse.json({ appointments: list }, { status: 200 });
  } catch (error) {
    console.error("Appointments GET error:", error);
    return NextResponse.json({ error: "Ошибка загрузки записей" }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const token = await getToken({
      req: request,
      secret: process.env.NEXTAUTH_SECRET,
    });
    if (!token?.id) {
      return NextResponse.json({ error: "Войдите в аккаунт" }, { status: 401 });
    }
    const patientId = parseInt(token.id as string);

    const patient = await prisma.patient.findUnique({ where: { id: patientId }, select: { id: true } });
    if (!patient) {
      return NextResponse.json({ error: "Пользователь не найден" }, { status: 404 });
    }

    const body = await request.json().catch(() => ({}));
    const { specialistId, serviceId, scheduledAt, durationMinutes = 30, note } = body;
    if (!specialistId || !scheduledAt) {
      return NextResponse.json({ error: "Укажите врача и дату/время" }, { status: 400 });
    }

    const specialist = await prisma.specialist.findUnique({ where: { id: parseInt(specialistId) }, select: { id: true } });
    if (!specialist) {
      return NextResponse.json({ error: "Врач не найден" }, { status: 400 });
    }

    let serviceIdNum: number | null = null;
    if (serviceId != null && serviceId !== "") {
      const s = await prisma.service.findFirst({
        where: { id: parseInt(serviceId) },
        select: { id: true },
      });
      if (s) serviceIdNum = s.id;
    }

    const scheduled = new Date(scheduledAt);
    if (Number.isNaN(scheduled.getTime())) {
      return NextResponse.json({ error: "Некорректная дата/время" }, { status: 400 });
    }

    if (typeof prisma.appointment?.create !== "function") {
      console.error("Prisma client: appointment model missing. Run: npx dotenv-cli -e .env -- npx prisma generate");
      return NextResponse.json({ error: "Ошибка конфигурации сервера" }, { status: 500 });
    }

    const appointment = await prisma.appointment.create({
      data: {
        patient_id: patientId,
        specialist_id: specialist.id,
        service_id: serviceIdNum,
        scheduled_at: scheduled,
        duration_minutes: durationMinutes || 30,
        status: "pending",
        note: note || null,
      },
    });

    return NextResponse.json({ appointment: { id: appointment.id, scheduled_at: appointment.scheduled_at } }, { status: 201 });
  } catch (error) {
    console.error("Appointments POST error:", error);
    return NextResponse.json({ error: "Ошибка создания записи" }, { status: 500 });
  }
}
